sql:
SELECT name
FROM components
ORDER BY name ASC;

SELECT total_downloads
FROM component_analytics
WHERE component_id = 1;

SELECT COUNT(component_id) AS recent_usage_count
FROM component_analytics
WHERE last_used >= DATE('now', '-30 days');

SELECT component_id
FROM component_analytics
ORDER BY usage_count DESC;

external_knowledge:
; A team is considered active if its status is 'active' in the teams table; 
A review is considered public if the 'is_public' field in the component_reviews table is set to 1; 
Component ratings are given on a scale of 1-5 stars, as indicated in the 'rating' column of the component_reviews table.

sql:
SELECT COUNT(DISTINCT component_id)
FROM component_analytics
WHERE usage_count > 0;

SELECT property_name
FROM component_properties
WHERE is_editable = 1;

external_knowledge:
; A component can have multiple versions, but only one current version; 
; A component can have multiple validation results, but the query only considers the result for the current version; 
; The validation result can be 'pass' or 'fail', but the query does not explicitly specify this.
